+fn reply_hgetdel_values(
+    ctx: &mut CommandContext,
+    values: Vec<Option<RedisString>>,
+) -> RedisResult<()> {
+    ctx.reply_array_header(values.len())?;
+    for value in values {
+        match value {
+            Some(s) => ctx.reply_bulk_string(s)?,
+            None => ctx.reply_null_bulk()?,
+        }
+    }
+    Ok(())
+}
